    [JsonSourceGenerationOptions(Converters = new[] { typeof(ResponseErrorJsonConverter) })]
    [JsonSerializable(typeof(ManagedServiceIdentityType))]
    [JsonSerializable(typeof(UserAssignedIdentity))]
    [JsonSerializable(typeof(ManagedServiceIdentity))]
    [JsonSerializable(typeof(OperationStatusResult))]
    [JsonSerializable(typeof(ResponseError))]
    [JsonSerializable(typeof(SystemData))]
    [JsonSerializable(typeof(SubResource))]
    [JsonSerializable(typeof(ExtendedLocation))]
    [JsonSerializable(typeof(ArmPlan))]
    [JsonSerializable(typeof(ArmEnvironment))]
    [JsonSerializable(typeof(Dictionary<string, string>))]
    [JsonSerializable(typeof(Dictionary<string, Dictionary<string, JsonElement>>))]
    internal partial class ResourceManagerJsonContext : JsonSerializerContext
    {
    }

    internal class ResponseErrorJsonConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            using var doc = JsonDocument.ParseValue(ref reader);
            var element = doc.RootElement;
            string code = element.TryGetProperty("code", out var c) ? c.GetString() : null;
            string message = element.TryGetProperty("message", out var m) ? m.GetString() : null;
            return new ResponseError(code, message);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WriteString("code"u8, value.Code);
            }
            if (value.Message != null)
            {
                writer.WriteString("message"u8, value.Message);
            }
            writer.WriteEndObject();
        }
    }
}

